module RefModule(
    input               clk     ,
    input               load    ,
    input               clr     ,
    input      [31:0]   data_in ,
    output reg [31:0]   acc_out 
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (clr)
        acc_out <= 32'd0;
    else if (load)
        acc_out <= data_in;
    else
        acc_out <= acc_out + data_in;
end

endmodule
